const items = $input.all();
const stripe = items.filter(i => i.json.data?.length && i.json.data[0]?.amount).flatMap(i => i.json.data || []);
const deals = items.filter(i => i.json.properties?.dealname);
const xeroInvoices = items.find(i => i.json.Invoices)?.json?.Invoices || [];

const criticals = [], warnings = [], infos = [];
const TOL = 0.01; // 1% tolerance
const BDAYS_TOL = 5;

// Helper: business days since date
function bizDays(dateStr) {
  const then = new Date(dateStr); const now = new Date();
  let days = 0; const cur = new Date(then);
  while (cur < now) {
    const d = cur.getDay(); if (d !== 0 && d !== 6) days++;
    cur.setDate(cur.getDate()+1);
  }
  return days;
}

// Check 1: Deals with no matching Stripe charge
deals.forEach(deal => {
  const amount = parseFloat(deal.json.properties?.amount?.value || 0);
  const closeDate = deal.json.properties?.closedate?.value;
  const name = deal.json.properties?.dealname?.value;
  if (!amount || amount < 100) return;
  const days = bizDays(closeDate);
  if (days < BDAYS_TOL) return;
  const match = stripe.find(c => Math.abs((c.amount/100) - amount) / amount < TOL);
  if (!match) criticals.push({ type: 'MISSING_PAYMENT', severity: 'CRITICAL', deal: name, amount, detail: `Deal ${name} (£${amount}) closed ${days} biz days ago — no matching Stripe charge found` });
});

// Check 2: Stripe charges with no HubSpot deal (>£500)
const deal_amounts = deals.map(d => parseFloat(d.json.properties?.amount?.value || 0));
stripe.filter(c => c.amount > 50000).forEach(charge => { // >£500
  const amt = charge.amount/100;
  const match = deal_amounts.find(a => Math.abs(a - amt) / amt < TOL);
  if (!match) warnings.push({ type: 'UNMATCHED_CHARGE', severity: 'WARNING', amount: amt, detail: `Stripe charge £${amt.toFixed(2)} on ${new Date(charge.created*1000).toLocaleDateString()} — no matching HubSpot deal found` });
});

// Check 3: Xero overdue invoices
xeroInvoices.filter(inv => inv.Type === 'ACCREC' && inv.AmountDue > 0).forEach(inv => {
  const overdue = bizDays(inv.DueDate);
  if (overdue > 30) criticals.push({ type: 'OVERDUE_INVOICE', severity: 'CRITICAL', detail: `Invoice ${inv.InvoiceNumber} for ${inv.Contact?.Name}: £${inv.AmountDue} — ${overdue} days overdue` });
  else if (overdue > 0) warnings.push({ type: 'OVERDUE_INVOICE', severity: 'WARNING', detail: `Invoice ${inv.InvoiceNumber}: £${inv.AmountDue} — ${overdue} days past due` });
});

return [{ json: { criticals, warnings, infos, has_criticals: criticals.length > 0, report_date: new Date().toLocaleDateString('en-GB'), clean_count: deals.length - criticals.length } }];

